import { dnaToKnot, knotToDna, toBytes, fromBytes } from '../src/runtime/packed-knot';
import { MAGIC } from '../src/lexicon';

/**
 * DNA V3 Reduction Benchmark
 * 
 * Compares Raw ASCII vs Gnosis V3 Binary (with RLE and Varints).
 */

const sequences = {
  "TP53-Exon": "",
  "Poly-A-100": "A".repeat(100),
  "Poly-A-1000": "A".repeat(1000),
  "Synthetic-Repeats": ("ACGT".repeat(25) + "AAAAA".repeat(20)).repeat(5)
};

console.log("# Gnosis DNA V3 Reduction Benchmark\n");
console.log("| Sequence | Raw (Bytes) | V3 (Bytes) | Reduction | bps (bits per base) |");
console.log("| :--- | :--- | :--- | :--- | :--- |");

for (const [name, dna] of Object.entries(sequences)) {
  const rawSize = dna.length;
  const knot = dnaToKnot(dna);
  const v3Bytes = toBytes(knot, { magic: MAGIC.DNA }); // Fixed call with magic
  const v3Size = v3Bytes.length;
  const reduction = ((rawSize - v3Size) / rawSize * 100).toFixed(2);
  const bpb = (v3Size * 8 / dna.length).toFixed(2);
  
  console.log(`| ${name} | ${rawSize} | ${v3Size} | ${reduction}% | ${bpb} |`);
  
  // Round-trip verification
  const restored = fromBytes(v3Bytes); // Fixed call
  const restoredDna = knotToDna(restored);
  if (restoredDna !== dna.toUpperCase().replace(/[^ACGT]/g, '')) {
    console.error(`ERROR: Round-trip failed for ${name}`);
  }
}
